./backend/node_modules/.prisma/client/index.js:428:  "inlineSchema": "// Phase1: Conversation, Message, Memory - see plan\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum ClaimType {\n  JUDGEMENT_PATTERN\n  VALUE\n  INTERACTION_PREFERENCE\n  EMOTIONAL_TENDENCY\n  RELATION_RHYTHM\n}\n\nenum ClaimStatus {\n  CANDIDATE\n  WEAK\n  STABLE\n  CORE\n  DEPRECATED\n}\n\nenum EvidencePolarity {\n  SUPPORT\n  CONTRA\n  NEUTRAL\n}\n\nmodel Conversation {\n  id                     String                  @id @default(uuid())\n  title                  String?\n  summarizedAt           DateTime?\n  /**\n   * 默认世界状态（地点/时区/语言等），用于意图补全与推理前提，不写入记忆\n   */\n  worldState             Json?\n  createdAt              DateTime                @default(now())\n  updatedAt              DateTime                @updatedAt\n  messages               Message[]\n  dailyMoments           DailyMoment[]\n  dailyMomentSuggestions DailyMomentSuggestion[]\n  dailyMomentSignals     DailyMomentSignal[]\n}\n\nmodel Message {\n  id             String       @id @default(uuid())\n  conversationId String\n  conversation   Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  role           String // 'user' | 'assistant'\n  content        String       @db.Text\n  tokenCount     Int? // D1: 该消息的估算 token 数（assistant 消息记录 LLM 实际输出 token）\n  createdAt      DateTime     @default(now())\n\n  @@index([conversationId, createdAt])\n}\n\nmodel Memory {\n  id               String   @id @default(uuid())\n  type             String // 'mid' | 'long'\n  category         String   @default(\"general\") // 'identity_anchor' | 'shared_fact' | 'commitment' | 'correction' | 'soft_preference' | 'general'\n  content          String   @db.Text\n  shortSummary     String?  @db.Text // 50-100 token 简短摘要，注入时优先使用（Phase3 可选）\n  sourceMessageIds String[] // PostgreSQL array for traceability\n  confidence       Float    @default(1)\n\n  // 衰减相关\n  hitCount       Int      @default(0) // 被召回/引用次数\n  lastAccessedAt DateTime @default(now()) // 最后一次被召回的时间\n  decayScore     Float    @default(1.0) // 衰减分，定期重算，0→候选删除\n  frozen         Boolean  @default(false) // true = 不参与衰减（identity_anchor 默认 frozen）\n\n  // 纠错专用\n  correctedMemoryId String? // 若本条是纠错记忆，指向被纠正的原记忆 ID\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([category])\n  @@index([decayScore])\n}\n\nmodel UserClaim {\n  id                   String          @id @default(uuid())\n  userKey              String          @default(\"default-user\")\n  type                 ClaimType\n  key                  String\n  valueJson            Json\n  confidence           Float\n  evidenceCount        Int             @default(0)\n  counterEvidenceCount Int             @default(0)\n  status               ClaimStatus     @default(CANDIDATE)\n  decayRate            Float?\n  contextTags          String[]        @default([])\n  sourceModels         String[]        @default([])\n  lastSourceMessageIds String[]        @default([])\n  lastSeenAt           DateTime        @default(now())\n  lastPromotedAt       DateTime?\n  createdAt            DateTime        @default(now())\n  updatedAt            DateTime        @updatedAt\n  evidences            ClaimEvidence[]\n\n  @@index([userKey, type, status])\n  @@index([userKey, type, key])\n  @@index([updatedAt])\n}\n\nmodel ClaimEvidence {\n  id          String           @id @default(uuid())\n  claimId     String\n  claim       UserClaim        @relation(fields: [claimId], references: [id], onDelete: Cascade)\n  userKey     String           @default(\"default-user\")\n  messageId   String?\n  sessionId   String?\n  snippet     String           @db.Text\n  polarity    EvidencePolarity\n  weight      Float            @default(1)\n  sourceModel String?\n  createdAt   DateTime         @default(now())\n\n  @@unique([claimId, messageId, polarity])\n  @@index([userKey, createdAt])\n  @@index([claimId, createdAt])\n}\n\nmodel SessionState {\n  id          String   @id @default(uuid())\n  userKey     String   @default(\"default-user\")\n  sessionId   String\n  stateJson   Json\n  confidence  Float\n  ttlSeconds  Int\n  observedAt  DateTime @default(now())\n  expiresAt   DateTime\n  sourceModel String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([userKey, sessionId, expiresAt])\n  @@index([userKey, expiresAt])\n  @@index([updatedAt])\n}\n\n// Phase2: 人格双池（结构化版）。支持版本化：保存时新建一条、旧条停用（isActive=false）\nmodel Persona {\n  id String @id @default(uuid())\n\n  // ── 人格层（稳定注入，几乎不变） ──\n  identity          String @default(\"\") @db.Text // 身份定位：我是谁、与用户的关系\n  personality       String @default(\"\") @db.Text // 性格特质\n  valueBoundary     String @default(\"\") @db.Text // 价值边界：判断原则、记忆哲学\n  behaviorForbidden String @default(\"\") @db.Text // 行为禁止项（替代 constraintKeys）\n\n  // ── 表达调度层（常驻但独立，允许更频繁微调） ──\n  voiceStyle        String @default(\"\") @db.Text // 语言风格基线\n  adaptiveRules     String @default(\"\") @db.Text // 自适应展开/收缩条件\n  silencePermission String @default(\"\") @db.Text // 留白与少说许可\n  metaFilterPolicy  String @default(\"\") @db.Text // 元过滤规则：禁止暴露内部策略/逻辑\n\n  // ── 进化约束 ──\n  evolutionAllowed   String @default(\"\") @db.Text // 允许的进化方向（自然语言）\n  evolutionForbidden String @default(\"\") @db.Text // 禁止的进化（自然语言，用于校验）\n\n  // ── 元数据 ──\n  version   Int      @default(1) // 版本号，保存时递增\n  isActive  Boolean  @default(true) // 是否当前启用；仅一条为 true\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  evolutionLogs PersonaEvolutionLog[]\n}\n\n// 人格进化日志：记录每次进化的字段变更，关联到 Persona 版本\nmodel PersonaEvolutionLog {\n  id        String   @id @default(uuid())\n  personaId String // 写入后的 Persona 版本 ID\n  persona   Persona  @relation(fields: [personaId], references: [id], onDelete: Cascade)\n  field     String // 目标字段名（identity/personality/...）\n  content   String   @db.Text // 追加的内容\n  reason    String   @db.Text // 变更理由\n  version   Int // 写入时的 Persona 版本号\n  createdAt DateTime @default(now())\n\n  @@index([personaId])\n}\n\nmodel UserProfile {\n  userKey                 String   @id\n  preferredVoiceStyle     String   @default(\"\") @db.Text\n  praisePreference        String   @default(\"\") @db.Text\n  responseRhythm          String   @default(\"\") @db.Text\n  impressionCore          String?  @db.Text // 核心印象，固定注入 system prompt，≤150 token\n  impressionDetail        String?  @db.Text // 可选细节，按需补充，≤500 token\n  pendingImpressionCore   String?  @db.Text // 待确认核心印象\n  pendingImpressionDetail String?  @db.Text // 待确认细节印象\n  createdAt               DateTime @default(now())\n  updatedAt               DateTime @updatedAt\n}\n\n// 身份锚定：独立于 Memory，始终注入、不衰减、支持多条目\nmodel IdentityAnchor {\n  id        String   @id @default(uuid())\n  userKey   String   @default(\"default-user\")\n  label     String // 'basic' | 'occupation' | 'interest' | 'custom'\n  content   String   @db.Text\n  sortOrder Int      @default(0)\n  nickname  String?\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// 身份锚定变更历史（审计日志）\nmodel IdentityAnchorHistory {\n  id              String   @id @default(uuid())\n  anchorId        String\n  previousContent String   @db.Text\n  newContent      String   @db.Text\n  changedAt       DateTime @default(now())\n}\n\n// 成长层：稳定的认知画像（独立于 Memory，便于长期演化）\nmodel CognitiveProfile {\n  id               String   @id @default(uuid())\n  kind             String // 'decision_pattern' | 'thinking_pattern' | 'support_preference' | ...\n  content          String   @db.Text\n  confidence       Float    @default(0.7)\n  sourceMessageIds String[] @default([])\n  hitCount         Int      @default(0)\n  lastAppliedAt    DateTime @default(now())\n  isActive         Boolean  @default(true)\n  status           String   @default(\"pending\") // 'pending' | 'confirmed' | 'rejected'\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  @@index([kind, isActive])\n  @@index([updatedAt])\n  @@index([status])\n}\n\n// 成长层：关系状态快照，按版本演化\nmodel RelationshipState {\n  id               String   @id @default(uuid())\n  stage            String // 'early' | 'familiar' | 'steady'\n  summary          String   @db.Text\n  trustScore       Float    @default(0.5)\n  closenessScore   Float    @default(0.5)\n  rhythmHint       String?\n  boundaryNotes    String[] @default([])\n  sourceMessageIds String[] @default([])\n  hitCount         Int      @default(0)\n  version          Int      @default(1)\n  isActive         Boolean  @default(true)\n  status           String   @default(\"pending\") // 'pending' | 'confirmed' | 'rejected'\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  @@index([isActive, updatedAt])\n  @@index([status])\n}\n\n// 成长层：边界治理事件，供后续审计与治理调优\nmodel BoundaryEvent {\n  id               String   @id @default(uuid())\n  note             String   @db.Text\n  severity         String   @default(\"info\")\n  sourceMessageIds String[] @default([])\n  createdAt        DateTime @default(now())\n\n  @@index([createdAt])\n  @@index([severity])\n}\n\n// 今日日记：表达产物表，不参与长期事实记忆\nmodel DailyMoment {\n  id               String       @id @default(uuid())\n  conversationId   String\n  conversation     Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  triggerMode      String\n  title            String\n  body             String       @db.Text\n  closingNote      String       @db.Text\n  moodTag          String?\n  sourceSnippetIds String[]     @default([])\n  sourceMessageIds String[]     @default([])\n  feedback         String?\n  createdAt        DateTime     @default(now())\n  updatedAt        DateTime     @updatedAt\n\n  @@index([conversationId, createdAt])\n  @@index([feedback])\n}\n\n// 今日日记轻提示：偶发触发提示记录\nmodel DailyMomentSuggestion {\n  id               String       @id @default(uuid())\n  conversationId   String\n  conversation     Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  hint             String       @db.Text\n  score            Float\n  moodTag          String?\n  sourceMessageIds String[]     @default([])\n  accepted         Boolean      @default(false)\n  acceptedAt       DateTime?\n  createdAt        DateTime     @default(now())\n\n  @@index([conversationId, createdAt])\n  @@index([accepted])\n}\n\n// 用户对今日日记功能的行为信号（喜欢/尴尬/再写一条/收藏回看）\nmodel DailyMomentSignal {\n  id             String       @id @default(uuid())\n  conversationId String\n  conversation   Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  type           String\n  sourceText     String?      @db.Text\n  createdAt      DateTime     @default(now())\n\n  @@index([conversationId, createdAt])\n  @@index([type])\n}\n\n// 工时上报记录：记录通过本工具成功提交的工时\nmodel TimesheetRecord {\n  id              String   @id @default(uuid())\n  date            DateTime @db.Date\n  totalHours      Int      @default(8)\n  projectsSummary Json // TimesheetSubmittedProject[]\n  submittedAt     DateTime @default(now())\n  createdAt       DateTime @default(now())\n\n  @@unique([date])\n  @@index([date])\n}\n\n// ── DevAgent ─────────────────────────────────────────────────\n\n// 开发代理会话：一次\"帮我改代码\"对话\nmodel DevSession {\n  id             String   @id @default(uuid())\n  conversationId String? // 可选：关联发起的聊天会话\n  title          String?\n  status         String   @default(\"active\") // active | completed | failed | cancelled\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n  runs           DevRun[]\n}\n\n// 开发代理执行记录：一次具体的执行动作\nmodel DevRun {\n  id           String     @id @default(uuid())\n  sessionId    String\n  session      DevSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  userInput    String     @db.Text\n  plan         Json?\n  status       String     @default(\"pending\") // pending | running | success | failed\n  executor     String? // shell | openclaw | codex\n  result       Json?\n  error        String?    @db.Text\n  artifactPath String?\n  startedAt    DateTime?\n  finishedAt   DateTime?\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  @@index([sessionId, createdAt])\n  @@index([status])\n}\n"
